SELECT [Detailed Vendor Ledg_ Entry].[Vendor Ledger Entry No_], [Detailed Vendor Ledg_ Entry].[Entry No_], [Detailed Vendor Ledg_ Entry].[Posting Date], Vendor.No_, [Detailed Vendor Ledg_ Entry].[Document No_], Vendor.Name, Vendor.[Name 2], Vendor.Address, Vendor.[Post Code], Vendor.City, Vendor.County, Vendor.[Country_region Code], Vendor.[VAT Registration No_], Vendor.[Fiscal Code], [Detailed Vendor Ledg_ Entry].[Currency Code], Sum(Val([Detailed Vendor Ledg_ Entry.Amount])) AS SaldoD, Sum(Val([Detailed Vendor Ledg_ Entry.Amount (LCY)])) AS SaldoVL, [Detailed Vendor Ledg_ Entry].[Transaction No_]
FROM [Detailed Vendor Ledg_ Entry] INNER JOIN Vendor ON [Detailed Vendor Ledg_ Entry].[Vendor No_] = Vendor.No_
WHERE ((([Detailed Vendor Ledg_ Entry].[Posting Date])<=[forms]![principale]![datafinale]))
GROUP BY [Detailed Vendor Ledg_ Entry].[Vendor Ledger Entry No_], [Detailed Vendor Ledg_ Entry].[Entry No_], [Detailed Vendor Ledg_ Entry].[Posting Date], Vendor.No_, [Detailed Vendor Ledg_ Entry].[Document No_], Vendor.Name, Vendor.[Name 2], Vendor.Address, Vendor.[Post Code], Vendor.City, Vendor.County, Vendor.[Country_region Code], Vendor.[VAT Registration No_], Vendor.[Fiscal Code], [Detailed Vendor Ledg_ Entry].[Currency Code], [Detailed Vendor Ledg_ Entry].[Transaction No_]
HAVING (((Vendor.No_)="F00043") AND ((Abs((Sum(Val([Detailed Vendor Ledg_ Entry.Amount (LCY)])))))>0.01));

